class Solution {
public:
    int maxLengthBetweenEqualCharacters(string s) {
        int firstOccurrence[26];
        int maxLength = -1;
        for (int i = 0; i < 26; i++) {
            firstOccurrence[i] = -1;
        }
        for (int i = 0; i < s.length(); i++) {
            int charIndex = s[i] - 'a';
            if (firstOccurrence[charIndex] == -1) {
                firstOccurrence[charIndex] = i;
            } else {
                maxLength = max(maxLength, i - firstOccurrence[charIndex] - 1);
            }
        }
        return maxLength;
    }
};
